    p_outputtruncated bool DEFAULT NULL
) RETURNS SETOF ${flyway:defaultSchema}."vwMCPToolExecutionLogs" AS $$
DECLARE
    v_new_id uuid;
BEGIN
    v_new_id := COALESCE(p_id, gen_random_uuid());
